unitsize(0.5 cm);

pair A, B, C, D;

A = (4,0);
B = (3,5);
C = (-2,4);
D = (-1,-1);

draw(A--B--C--D--cycle);

dot("$4$", A, SE);
dot("$3 + 5i$", B, NE);
dot("$-2 + 4i$", C, NW);
